// src/pages/vendor/VendorPortal.jsx
import React, { useState, useEffect } from 'react';
import { CheckCircle2, Navigation2, MapPin, Clock } from 'lucide-react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { Badge, ComplaintCard, VendorComplaintModal } from '../../components/ComplaintCard';
import { KPI, ProgressBar, NotifBanner } from '../../components/UI';
import LiveMap from '../../components/LiveMap';
import { timeAgo, calcResolutionRate, avgResolutionTime } from '../../utils/helpers';

// Firebase Imports
import { db } from '../../utils/firebase'; 
import { doc, getDoc, setDoc, deleteDoc, collection, onSnapshot, serverTimestamp } from 'firebase/firestore';

const BTN = ({ children, onClick, color='#1565C0', outline=false, small=false, type="button" }) => (
  <button type={type} onClick={onClick} style={{
    padding: small?'6px 12px':'8px 15px', borderRadius:9, fontSize:small?12:13, fontWeight:600, cursor:'pointer',
    background: outline?'#fff':color, color:outline?color:'#fff',
    border: outline?`1px solid ${color}`:'none', transition:'all .15s',
    display:'inline-flex', alignItems:'center', gap:5,
  }}>{children}</button>
);

/* ── GLOBAL FULL IMAGE LIGHTBOX MODAL ── */
function ImageLightbox({ imageUrl, onClose }) {
  if (!imageUrl) return null;
  return (
    <div onClick={onClose} style={{ position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh', backgroundColor: 'rgba(10, 22, 40, 0.95)', zIndex: 99999, display: 'flex', alignItems: 'center', justifyContent: 'center', backdropFilter: 'blur(5px)', cursor: 'zoom-out' }}>
      <div style={{ position: 'relative', maxWidth: '95%', maxHeight: '95%' }} onClick={e => e.stopPropagation()}>
        <img src={imageUrl} alt="Evidence Asset" style={{ maxWidth: '100%', maxHeight: '90vh', borderRadius: '16px' }} />
        <button onClick={onClose} style={{ position: 'absolute', top: 20, right: 20, background: 'rgba(13, 17, 23, 0.8)', border: 'none', color: '#fff', fontSize: '16px', cursor: 'pointer', width: 34, height: 34, borderRadius: '50%' }}>✕</button>
      </div>
    </div>
  );
}

/* ── SUB-TAB 1: TASK INBOX ── */
function TaskInbox({ tasks, onAction, onSelect, onOpenAssignModal, onViewImage }) {
  const active = tasks.filter(c => !['COMPLETED','REJECTED'].includes(c.status));
  return (
    <>
      <div className="page-hd">
        <div className="page-title">My Tasks Workspace</div>
        <div className="page-sub">Nagpur Junction (Live Nodes) · {new Date().toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long'})}</div>
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(110px,1fr))',gap:10,marginBottom:16}}>
        <KPI label="Total"  value={tasks.length} />
        <KPI label="New"    value={tasks.filter(c=>c.status==='NEW').length}         color="#E65100" />
        <KPI label="Active" value={tasks.filter(c=>['ACCEPTED','ASSIGNED_TO_CLEANER','CLEANED_BY_FORCE'].includes(c.status)).length} color="#1565C0" />
        <KPI label="Done"   value={tasks.filter(c=>c.status==='COMPLETED').length}   color="#2E7D32" />
      </div>
      {active.length===0
        ? <div style={{background:'#fff',border:'1px solid #DDE3E9',borderRadius:14,padding:36,textAlign:'center',color:'#7A8FA6'}}>No pending cleaning tracks available.</div>
        : <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>
            {active.map(c => (
              <ComplaintCard key={c.id} complaint={c} onClick={() => onSelect(c)} onViewImage={onViewImage} actions={
                <div style={{ display: 'flex', flexDirection: 'column', gap: 6, width: '100%' }}>
                  {c.status==='NEW' && <BTN onClick={e=>{e.stopPropagation(); onAction(c.id,'ACCEPTED')}} color="#1565C0">Accept</BTN>}
                  {c.status==='ACCEPTED' && <BTN onClick={e=>{e.stopPropagation(); onOpenAssignModal(c)}} color="#4527A0">Assign Cleaner</BTN>}
                  {c.status==='ASSIGNED_TO_CLEANER' && (
                    <div style={{fontSize:11, color:'#e65100', fontWeight:700, background:'#fff3e0', padding:6, borderRadius:6, textAlign:'center'}}>
                      Cleaner Working: {c.assignedTo || 'On Duty'}
                    </div>
                  )}
                  {c.status==='CLEANED_BY_FORCE' && (
                    <div style={{ background: '#e8f5e9', padding: 8, borderRadius: 8, border: '1px solid #2e7d32' }}>
                      <div style={{ fontSize: 10, fontWeight: 700, color: '#2e7d32', marginBottom: 4 }}>Cleaner Proof Image (Click to View):</div>
                      {c.cleanerPhoto && (
                        <img 
                          src={c.cleanerPhoto} 
                          alt="Proof Asset" 
                          onClick={(e) => { e.stopPropagation(); onViewImage(c.cleanerPhoto); }}
                          style={{ width: '100%', height: 80, objectFit: 'cover', borderRadius: 6, marginBottom: 6, cursor: 'zoom-in' }} 
                        />
                      )}
                      <BTN onClick={e=>{e.stopPropagation(); onAction(c.id,'COMPLETED')}} color="#2E7D32">Complete Task</BTN>
                    </div>
                  )}
                  <BTN onClick={e=>{e.stopPropagation(); onSelect(c)}} outline color="#546E7A" small>View Popup</BTN>
                </div>
              }/>
            ))}
          </div>
      }
    </>
  );
}

/* ── SUB-TAB 2: TASK MAP ── */
function TaskMap({ tasks, onSelect }) {
  const active = tasks.filter(c => c.lat && c.lng);
  return (
    <>
      <div className="page-hd"><div className="page-title">Live Node GIS Map</div><div className="page-sub">Real-time GPS parameters</div></div>
      <LiveMap complaints={active} height="320px" onPinClick={onSelect} />
    </>
  );
}

/* ── SUB-TAB 3: CLEANERS CRUD CONTROL (With Password Parameter) ── */
function DynamicCleanersTab({ cleaners, onAddCleaner, onDeleteCleaner }) {
  const [cName, setCName] = useState('');
  const [cPhone, setCPhone] = useState('');
  const [cPassword, setCPassword] = useState('');
  const [showPasswordId, setShowPasswordId] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!cName.trim() || !cPhone.trim() || !cPassword.trim()) {
      return alert("Please fill all details including the login password.");
    }
    onAddCleaner({ name: cName.trim(), phone: cPhone.trim(), password: cPassword.trim() });
    setCName(''); setCPhone(''); setCPassword('');
  };

  return (
    <>
      <div className="page-hd">
        <div className="page-title">Cleaner Staff Management</div>
        <div className="page-sub">Manage ground deployment crews & access authentication</div>
      </div>
      
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexWrap: 'wrap', gap: 12, background: '#fff', padding: 16, borderRadius: 12, border: '1px solid #DDE3E9', marginBottom: 20, alignItems: 'flex-end' }}>
        <div style={{ flex: '1 1 200px' }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>CLEANER NAME</span>
          <input type="text" value={cName} onChange={e => setCName(e.target.value)} placeholder="e.g. Ramesh Kumar" style={{ width: '100%', padding: '8px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9', boxSizing: 'border-box' }} />
        </div>
        <div style={{ flex: '1 1 200px' }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>PHONE NUMBER / LOGIN ID</span>
          <input type="text" value={cPhone} onChange={e => setCPhone(e.target.value)} placeholder="e.g. 9876543210" style={{ width: '100%', padding: '8px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9', boxSizing: 'border-box' }} />
        </div>
        <div style={{ flex: '1 1 180px' }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>APP PASSWORD</span>
          <input type="password" value={cPassword} onChange={e => setCPassword(e.target.value)} placeholder="Set Password" style={{ width: '100%', padding: '8px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9', boxSizing: 'border-box' }} />
        </div>
        <BTN type="submit" color="#2E7D32">+ Onboard Staff</BTN>
      </form>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(280px,1fr))', gap: 14 }}>
        {cleaners.length === 0 ? (
          <div style={{color:'#7A8FA6', fontSize:13}}>No staff onboarded yet. Add staff above.</div>
        ) : cleaners.map(c => (
          <div key={c.id} style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 14, padding: 16, display:'flex', alignItems:'center', justifyContent:'space-between', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: 14, color:'#0A1628' }}>🧹 {c.name}</div>
              <div style={{ fontSize: 11, color: '#7A8FA6', marginTop: 3 }}>User/Phone: <strong style={{color: '#1565C0'}}>{c.phone}</strong></div>
              <div style={{ fontSize: 11, color: '#7A8FA6', marginTop: 2, display: 'flex', alignItems: 'center', gap: 5 }}>
                <span>Password:</span> 
                <span style={{ fontFamily: 'monospace', fontWeight: 'bold', color: '#27272A' }}>
                  {showPasswordId === c.id ? c.password : '••••••••'}
                </span>
                <button 
                  type="button" 
                  onClick={() => setShowPasswordId(showPasswordId === c.id ? null : c.id)}
                  style={{ background: 'none', border: 'none', color: '#1565C0', fontSize: 10, cursor: 'pointer', padding: 0, fontWeight: 600 }}
                >
                  {showPasswordId === c.id ? '[Hide]' : '[Show]'}
                </button>
              </div>
            </div>
            <button onClick={() => onDeleteCleaner(c.id)} style={{ background: '#FFEBEE', border: 'none', color: '#B71C1C', fontSize: 14, cursor: 'pointer', width: 32, height: 32, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>🗑️</button>
          </div>
        ))}
      </div>
    </>
  );
}

/* ── SUB-TAB 4: STATS ── */
function VendorStats({ tasks }) {
  const rate = calcResolutionRate(tasks);
  const avg  = avgResolutionTime(tasks);
  return (
    <>
      <div className="page-hd"><div className="page-title">Performance Diagnostics</div><div className="page-sub">Live SLA Analytics</div></div>
      <div style={{background:'#fff',border:'1px solid #DDE3E9',borderRadius:14,padding:18, maxWidth:400}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:14}}>Resolution Efficiency</div>
        <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:12}}>
          <div style={{width:70,height:70,borderRadius:'50%',background:`conic-gradient(#2E7D32 0% ${rate}%,#ECEFF1 ${rate}% 100%)`,position:'relative',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:800}}>{rate}%</div>
          <div>
            <div style={{fontSize:12,color:'#7A8FA6'}}>Avg Speed Latency</div>
            <div style={{fontWeight:700}}>{avg} Minutes</div>
          </div>
        </div>
        <ProgressBar value={rate} color="#2E7D32" height={6} />
      </div>
    </>
  );
}

/* ── MAIN VENDOR DASHBOARD ARCHITECTURE ── */
export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  
  // Login Authentication States
  const [isVendorLoggedIn, setIsVendorLoggedIn] = useState(false);
  const [vendorLoginId, setVendorLoginId] = useState('');
  const [vendorPassword, setVendorPassword] = useState('');
  const [currentVendorData, setCurrentVendorData] = useState(null);

  // Layout States
  const [tab, setTab] = useState('tasks');
  const [selected, setSelected] = useState(null);
  const [notif, setNotif] = useState(null);
  const [assignModalTask, setAssignModalTask] = useState(null);
  const [activeLightboxImage, setActiveLightboxImage] = useState(null);
  
  // Cleaners CRUD State
  const [cleaners, setCleaners] = useState([]);

  // Esc Key to close image
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && activeLightboxImage) setActiveLightboxImage(null);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [activeLightboxImage]);

  // Cleaners List real-time Firestore synchronization
  useEffect(() => {
    if (!isVendorLoggedIn || !vendorLoginId) return;
    
    // प्रत्येक Vendor के अपने क्लीनर की सब-कलेक्शन लिस्ट होगी
    const unsubscribe = onSnapshot(collection(db, "vendors", vendorLoginId.trim(), "cleaners"), (snap) => {
      setCleaners(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    return () => unsubscribe();
  }, [isVendorLoggedIn, vendorLoginId]);

  // Vendor Verification Handler
  const handleVendorAuthCheck = async (e) => {
    e.preventDefault();
    if (!vendorLoginId.trim() || !vendorPassword) return alert("Fill all entry fields.");
    try {
      const docRef = doc(db, "vendors", vendorLoginId.trim());
      const res = await getDoc(docRef);
      
      if (res.exists() && res.data().password === vendorPassword) {
        setCurrentVendorData(res.data());
        setIsVendorLoggedIn(true);
      } else {
        alert("Invalid Vendor Credential Parameters.");
      }
    } catch (err) {
      alert("Error checking vendor backend authentication configuration.");
    }
  };

  // Cleaner Add (Create Operation with explicit login password)
  const handleAddCleaner = async (payload) => {
    try {
      const newCleanerRef = doc(collection(db, "vendors", vendorLoginId.trim(), "cleaners"));
      await setDoc(newCleanerRef, {
        name: payload.name,
        phone: payload.phone,
        password: payload.password, // Added clear-text password for cleaner cluster login structure
        createdAt: serverTimestamp()
      });
      setNotif(`Staff ${payload.name} onboarded successfully.`);
    } catch (err) {
      alert("Failed to add cleaner staff to cluster database.");
    }
  };

  // Cleaner Delete (Delete Operation)
  const handleRangeDeleteCleaner = async (cleanerId) => {
    if (!window.confirm("Remove this cleaner personnel from system grid?")) return;
    try {
      await deleteDoc(doc(db, "vendors", vendorLoginId.trim(), "cleaners", cleanerId));
      setNotif("Staff profile pruned from node.");
    } catch (err) {
      alert("Error deleting cleaner staff entry.");
    }
  };

  const currentSelected = complaints.find(c => c.id === selected?.id) || selected;

  const act = async (id, status) => {
    if (status === 'COMPLETED') {
      await updateComplaint(id, { status, cleanerStatus: 'DONE', resolvedAt: new Date() });
    } else {
      await updateComplaint(id, { status });
    }
    const msgs = { ACCEPTED:'Task accepted, await cleaner allocation.', COMPLETED:'Registry closed! Verified clean.' };
    setNotif(msgs[status] || 'State updated successfully');
  };

  const handleAssignCleaner = async (cleanerName) => {
    if (!assignModalTask) return;
    await updateComplaint(assignModalTask.id, {
      status: 'ASSIGNED_TO_CLEANER',
      assignedTo: cleanerName,
      cleanerStatus: 'ASSIGNED'
    });
    setNotif(`Task assigned to ${cleanerName}`);
    setAssignModalTask(null);
  };

  // Filter complaints based on Vendor's assigned station
  const filteredComplaints = currentVendorData?.stationName 
    ? complaints.filter(c => {
        const compStation = typeof c.station === 'object' ? c.station?.name : c.station;
        return compStation === currentVendorData.stationName;
      })
    : complaints;

  const navItems = [
    { key:'tasks', icon: '📋', label:'Tasks', count: filteredComplaints.filter(c=>['NEW', 'ACCEPTED', 'ASSIGNED_TO_CLEANER', 'CLEANED_BY_FORCE'].includes(c.status)).length },
    { key:'map',   icon: '🗺️', label:'Task Map' },
    { key:'cleaners', icon: '🧹', label:'Manage Cleaners' },
    { key:'done',  icon: '✅', label:'Completed History' },
    { key:'stats', icon: '📊', label:'Analytics' },
  ];

  /* ── GATE 1: AUTHENTICATION LOCK INTERFACE ── */
  if (!isVendorLoggedIn) {
    return (
      <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center', background: '#0F172A' }}>
        <form onSubmit={handleVendorAuthCheck} style={{ background: '#fff', padding: '32px 28px', borderRadius: 16, width: 340, boxShadow: '0 10px 40px rgba(0,0,0,0.25)' }}>
          <div style={{ fontSize: 20, fontWeight: 800, color: '#1E293B', marginBottom: 6, textAlign: 'center' }}>Express Travel Hub</div>
          <div style={{ fontSize: 13, color: '#64748B', marginBottom: 24, textAlign: 'center', fontWeight: 500 }}>Vendor Workstation Node Login</div>
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#475569', marginBottom: 5 }}>VENDOR LOGIN ID</label>
          <input type="text" value={vendorLoginId} onChange={e => setVendorLoginId(e.target.value)} placeholder="e.g. vendor_ngp_01" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 14, boxSizing: 'border-box', fontSize: 13 }} />
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#475569', marginBottom: 5 }}>ACCESS PASSWORD</label>
          <input type="password" value={vendorPassword} onChange={e => setVendorPassword(e.target.value)} placeholder="••••••••" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 20, boxSizing: 'border-box', fontSize: 13 }} />
          
          <button type="submit" style={{ width: '100%', padding: 11, background: '#1565C0', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, fontSize: 13, cursor:'pointer' }}>Authenticate Workstation</button>
        </form>
      </div>
    );
  }

  /* ── GATE 2: VERIFIED DASHBOARD WORKSPACE ── */
  return (
    <div style={{display:'flex',height:'100vh',fontFamily:'system-ui,sans-serif',overflow:'hidden'}}>
      <Sidebar 
        title="Express Travel" 
        subtitle={currentVendorData?.name || "Vendor Engine"} 
        navItems={navItems} 
        activeTab={tab} 
        onTabChange={setTab}
        footerUser={{initials:'VN', name: currentVendorData?.name || 'Vendor Head', role: currentVendorData?.stationName || 'Field Lead', avatarColor:'#1565C0'}}
      />
      
      <div style={{flex:1,overflowY:'auto',background:'#F7F9FC'}}>
        {notif && <NotifBanner msg={notif} type="green" onDone={()=>setNotif(null)}/>}
        <div style={{padding:22,maxWidth:900,margin:'0 auto', width:'100%'}}>
          
          {tab==='tasks' && <TaskInbox tasks={filteredComplaints} onAction={act} onSelect={setSelected} onOpenAssignModal={setAssignModalTask} onViewImage={setActiveLightboxImage}/>}
          
          {tab==='map'   && <TaskMap   tasks={filteredComplaints} onSelect={setSelected}/>}
          
          {tab==='cleaners' && <DynamicCleanersTab cleaners={cleaners} onAddCleaner={handleAddCleaner} onDeleteCleaner={handleRangeDeleteCleaner} />}
          
          {tab==='done'  && (
            <>
              <div className="page-hd"><div className="page-title">Archive Logs</div></div>
              <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>
                {filteredComplaints.filter(c=>c.status==='COMPLETED').map(c=><ComplaintCard key={c.id} complaint={c} onClick={()=>setSelected(c)} onViewImage={setActiveLightboxImage}/>)}
              </div>
            </>
          )}
          
          {tab==='stats' && <VendorStats tasks={filteredComplaints}/>}
        </div>
      </div>
      
      {/* Dynamic Assignment Dropdown Overlay using Firebase Crew State */}
      {assignModalTask && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999}}>
          <div style={{background:'#fff',padding:20,borderRadius:12,width:280,boxShadow:'0 4px 20px rgba(0,0,0,0.15)'}}>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:'#0A1628'}}>Select Cleaner Personnel</div>
            <div style={{display:'flex',flexDirection:'column',gap:8, maxHeight:200, overflowY:'auto'}}>
              {cleaners.length === 0 ? (
                <div style={{fontSize:12, color:'#7A8FA6', textAlign:'center', padding:10}}>No cleaners available. Add them in Cleaners tab first.</div>
              ) : cleaners.map(c => (
                <button key={c.id} onClick={() => handleAssignCleaner(c.name)} style={{padding:10,background:'#f7f9fc',border:'1px solid #dde3e9',borderRadius:8,cursor:'pointer',textAlign:'left',fontWeight:600}}>
                  👤 {c.name}
                </button>
              ))}
            </div>
            <button onClick={() => setAssignModalTask(null)} style={{marginTop:12,width:'100%',padding:6,background:'#ECEFF1',border:'none',borderRadius:6,fontWeight:600,cursor:'pointer',fontSize:12}}>Cancel</button>
          </div>
        </div>
      )}

      {selected && (
        <VendorComplaintModal 
          complaint={currentSelected} 
          onClose={()=>setSelected(null)} 
          onAction={(id,s)=>act(id,s)}
          onViewImage={setActiveLightboxImage}
        />
      )}

      <ImageLightbox imageUrl={activeLightboxImage} onClose={() => setActiveLightboxImage(null)} />

      <style>{`
        .page-hd{margin-bottom:18px}.page-title{font-size:18px;font-weight:800;color:#0D1117;margin-bottom:2px}.page-sub{font-size:12px;color:#7A8FA6}
      `}</style>
    </div>
  );
}
